const agentOutput = $input.first().json;

try {
  let parsedData;
  let parseError = null;

  const rawText = agentOutput.output || agentOutput.text || JSON.stringify(agentOutput);

  console.log("Raw AI output:", rawText);

  // Clean markdown code blocks
  let cleanedText = rawText
    .replace(/```json\s*/g, '')
    .replace(/```\s*/g, '')
    .trim();

  console.log("Cleaned text:", cleanedText);

  try {
    // Try to parse the cleaned JSON
    parsedData = JSON.parse(cleanedText);
  } catch (err) {
    console.log("JSON parsing failed, attempting manual extraction");
    parseError = err;

    // Manual extraction as fallback
    const titleMatch = cleanedText.match(/"title"\s*:\s*"([^"]+)"/);
    const title = titleMatch ? titleMatch[1] : "Untitled Case Study";

    // Extract content
    const contentMatch = cleanedText.match(/"content"\s*:\s*"([\s\S]+?)"\s*,?\s*"meta"/m) || 
                         cleanedText.match(/"content"\s*:\s*"([\s\S]+?)"\s*\}/m);
    let extractedContent = contentMatch ? contentMatch[1] : cleanedText;

    // Unescape JSON sequences
    extractedContent = extractedContent
      .replace(/\\n/g, '\n')
      .replace(/\\"/g, '"')
      .replace(/\\'/g, "'")
      .replace(/\\\\/g, '\\')
      .replace(/\\t/g, '\t');

    // Try to extract meta if present
    const metaMatch = cleanedText.match(/"meta"\s*:\s*\{([\s\S]+?)\}\s*\}/);
    let meta = { angle: 'unknown', tone: 'unknown', reasoning: 'Parse error occurred' };

    if (metaMatch) {
      try {
        const metaJson = '{' + metaMatch[1] + '}';
        meta = JSON.parse(metaJson);
      } catch (e) {
        console.log('Meta parsing failed:', e);
      }
    }

    parsedData = {
      title: title,
      content: extractedContent,
      meta: meta
    };
  }

  // Log the strategy for monitoring
  console.log('Case Study Strategy:', JSON.stringify(parsedData.meta, null, 2));

  // Return the extracted data
  return {
    json: {
      title: parsedData.title || "Untitled Case Study",
      content: parsedData.content || "",
      meta: parsedData.meta || { angle: 'unknown', tone: 'unknown' },
      warning: parseError ? "JSON was malformed and manually extracted" : null,
      debug_raw: rawText.substring(0, 200)
    }
  };

} catch (error) {
  // Complete fallback
  return {
    json: {
      title: "Error Extracting Case Study",
      content: `Error: ${error.message}`,
      meta: { error: true },
      rawData: JSON.stringify(agentOutput).substring(0, 500)
    }
  };
}

const caseStudy = $input.first().json;

// Extract meta information
const meta = caseStudy.meta || {};

// Create a readable summary for logging
const summary = {
