  strategy: {
    angle: meta.angle || 'not specified',
    tone: meta.tone || 'not specified',
    title_formula: meta.title_formula || 'not specified',
    features_highlighted: meta.features_highlighted || [],
    reasoning: meta.reasoning || 'not provided'
  },
  timestamp: new Date().toISOString()
};

console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
console.log('CASE STUDY GENERATED:');
console.log(JSON.stringify(summary, null, 2));
console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');

// Pass through the data
return {
  json: caseStudy
};
